#include <stdio.h>
int main(){
    int T; scanf("%d", &T);
    while(T--){
        int N; long long C; scanf("%d %lld", &N, &C);
        long long sum = 0; for(int i=0;i<N;i++){ int a; scanf("%d", &a); sum += a; }
        if(sum <= C) printf("Yes\n"); else printf("No\n");
    }
    return 0;
}

